#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    int X;
    double Y;
    cin >> X >> Y;

    if (X % 5 == 0 && X + 0.50 <= Y) {
        Y -= (X + 0.50);
    }

    cout << fixed << setprecision(2) << Y << endl;
    return 0;
}

