code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

rl.question('', (input) => {
    let [X, Y] = input.split(' ').map(Number);

    if (X % 5 === 0 && X + 0.50 <= Y) {
        Y -= (X + 0.50);
    }

    console.log(Y.toFixed(2));
    rl.close();
});
